const DIALOGUSERS = "GET_LIST_DIALOGUSERS";

type getDialogListActionType = {
    type: typeof DIALOGUSERS,
    payload: any,
};
export const getDialogListActin = (payload: any): getDialogListActionType => ({ type: DIALOGUSERS, payload });
